import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, Info, Plus, Search, MessageCircle, HelpCircle, LayoutDashboard, Users
} from 'lucide-react';

const Login = () => {
  // --- STATE ---
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showModal, setShowModal] = useState(false);
  const [userRequests, setUserRequests] = useState([]); 
  const [selectedFileName, setSelectedFileName] = useState(""); 

  // --- 1. MODERN NATIVE FILE PICKER LOGIC ---
  // This avoids the messy browser "Recent Downloads" bar
  const handleNativeUpload = async () => {
    try {
      // This is the "Magic" API that opens the REAL System Dialog directly
      const [fileHandle] = await window.showOpenFilePicker({
        types: [
          {
            description: 'Documents',
            accept: { 'image/*': ['.png', '.gif', '.jpeg', '.jpg'], 'application/pdf': ['.pdf'] }
          },
        ],
        excludeAcceptAllOption: false,
        multiple: false
      });

      const file = await fileHandle.getFile();
      setSelectedFileName(file.name);
      alert(`📂 Selected from System: ${file.name}`);
    } catch (err) {
      console.log("User cancelled or browser not supported:", err);
    }
  };

  // --- PERSISTENCE & AUTH (Keeping your existing logic) ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    if (token) {
      if (role === 'admin') setView('admin-dashboard');
      else setView('dashboard');
    }
  }, []);

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const requestBody = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "application_doc.pdf"
    };
    try {
      await axios.post('http://localhost:5000/api/requests/submit', requestBody);
      setShowModal(false);
      setSelectedFileName("");
      alert("✅ Submitted Successfully!");
      setActiveTab('tracking'); 
    } catch (err) { alert("Submission Error"); }
  };

  // (Landing and Form views omitted for brevity - Keep yours as is)
  if (view === 'landing') return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        <div className="text-center mb-12">
           <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
           <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase">QUAD SOLUTIONS</h1>
           <p className="text-slate-500 font-medium italic">Credentialing Engine</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 max-w-4xl w-full">
          <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition group">
             <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mb-6 text-blue-600"><UserPlus size={32} /></div>
             <h2 className="text-2xl font-black mb-2">New Providers</h2>
             <div className="flex items-center text-blue-600 font-bold">Get Started <ArrowRight size={20} className="ml-2" /></div>
          </div>
          <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition group">
             <div className="w-16 h-16 bg-white/10 rounded-2xl flex items-center justify-center mb-6 text-blue-400"><LogIn size={32} /></div>
             <h2 className="text-2xl font-black mb-2">Existing Clients</h2>
             <div className="flex items-center text-blue-400 font-bold">Sign In <ArrowRight size={20} className="ml-2" /></div>
          </div>
        </div>
    </div>
  );

  // USER DASHBOARD RENDER
  return (
    <div className="min-h-screen bg-slate-50 flex flex-col relative overflow-hidden">
      <nav className="bg-white shadow-sm p-4 border-b">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
          <div className="flex gap-4 items-center">
             <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
             <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>My Status</button>
             <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold p-2"><LogOut size={20}/></button>
          </div>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto w-full">
        {activeTab === 'services' ? (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8 tracking-tighter uppercase italic">Service Catalog</h2>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map((title, idx) => (
                  <div key={idx} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition">
                    <div className="w-12 h-12 bg-blue-50 rounded-xl flex items-center justify-center mb-4 text-blue-600"><FileText/></div>
                    <h3 className="text-xl font-bold mb-4">{title}</h3>
                    <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl font-bold hover:bg-blue-600 transition uppercase text-xs italic">Apply Now</button>
                  </div>
                ))}
             </div>
          </section>
        ) : (
          <section className="animate-in fade-in duration-500">
             <h2 className="text-3xl font-black text-slate-900 mb-8 uppercase italic tracking-tighter">Tracking History</h2>
             {userRequests.map((req) => (
               <div key={req._id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex justify-between items-center mb-4">
                 <div className="font-black text-slate-800 uppercase text-xs tracking-widest">{req.type}</div>
                 <div className="bg-blue-100 text-blue-600 px-4 py-2 rounded-full text-[10px] font-black uppercase italic tracking-widest">ID: {req.licenseNumber}</div>
               </div>
             ))}
          </section>
        )}
      </main>

      {/* --- THE SUBMISSION MODAL --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] shadow-2xl p-10 animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-6 text-blue-600 uppercase italic underline underline-offset-8">New Submission</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl border-none font-bold text-slate-700 outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License ID" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" required />
              
              {/* --- CLICKING THIS BOX TRIGGERS THE MODERN SYSTEM DIALOG --- */}
              <div 
                onClick={handleNativeUpload} 
                className="mt-1 p-8 bg-blue-50 rounded-2xl border-2 border-dashed border-blue-200 text-center cursor-pointer hover:bg-blue-100 transition group"
              >
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={28}/>
                <p className="text-[10px] font-black text-blue-600 uppercase tracking-tighter">
                   {selectedFileName ? `SELECTED: ${selectedFileName}` : "Click to Upload Document"}
                </p>
                <p className="text-[10px] text-slate-400 mt-1 italic">Opens native explorer directly</p>
              </div>

              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black mt-4 shadow-xl shadow-blue-100">Confirm Submission</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-400 font-bold text-sm hover:text-slate-600 transition">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
